class ChessEnvironment:
 def __init__(self):
 self.board = self._init_board()
 self.current_player = 'white'

 def is_fully_observable(self):
 return True # Complete board state visible

 def is_deterministic(self):
 return True # Each move has exact outcome

 def is_static(self):
 return True # Board only changes with moves

 def is_discrete(self):
 return True # Finite board positions

 def is_multi_agent(self):
 return True # Two players

 def is_adversarial(self):
 return True # Players compete

 def get_state(self):
 """Returns complete board state"""
 return self.board.copy()

 def step(self, move):
 """Execute deterministic move"""
 start, end = move
 piece = self.board[start]
 self.board[end] = piece
 self.board[start] = None
 self.current_player = 'black' if self.current_player == 'white' else 'white'
 return self.get_state(), self._evaluate(), self._is_game_over()

 def _init_board(self):
 # Initialize standard chess board
 return {}

 def _evaluate(self):
 # Material and position evaluation
 return 0

 def _is_game_over(self):
 return False

class DrivingEnvironment:
 def __init__(self):
 self.state = {
 'position': 0.0,
 'velocity': 0.0,
 'other_cars': [],
 'traffic_lights': 'green'
 }
 self.sensor_range = 100 # meters

 def is_fully_observable(self):
 return False # Cannot see everything

 def is_deterministic(self):
 return False # Traffic is unpredictable

 def is_static(self):
 return False # Other cars move independently

 def is_discrete(self):
 return False # Continuous position/velocity values

 def get_pertceived_state(self):
 """Returns only observable portion of state"""
 perceived = {}
 # Only perceive objects within sensor range
 for car in self.state['other_cars']:
 if abs(car['position'] - self.state['position']) < self.sensor_range:
 perceived['visible_cars'] = car
 perceived['velocity'] = self.state['velocity']
 perceived['traffic_lights'] = self.state['traffic_lights']
 return perceived

 def step(self, action):
 """Execute action with stochastic outcomes"""
 # Agent's action
 if action == 'accelerate':
 self.state['velocity'] += 1.0
 elif action == 'brake':
 self.state['velocity'] -= 1.5

 # Environment changes stochastically
 self._update_traffic()
 self._update_other_cars()

 # Calculate reward (safety, progress)
 reward = self._calculate_reward()
 done = self._check_collision()

 return self.get_pertceived_state(), reward, done

 def _update_traffic(self):
 # Random traffic light changes
 import random
 lights = ['green', 'yellow', 'red']
 if random.random() < 0.1:
 self.state['traffic_lights'] = random.choice(lights)

 def _update_other_cars(self):
 # Other cars move unpredictably
 import random
 for car in self.state['other_cars']:
 car['position'] += car['velocity'] + random.uniform(-0.5, 0.5)

 def _calculate_reward(self):
 return self.state['velocity']

 def _check_collision(self):
 return False
